            if c.totals.total_billed == Decimal("64000.00")
            and c.totals.total_payable == Decimal("41400.00")
        ),
        None,
    )
    if claim is None:
        raise NotFound("worked-example claim not found; run reset_demo_data first")
    return get_claim(session, claim.id)

